         macdValue = prevFast - prevSlow;
         prevSignal = Math.fma(macdValue - prevSignal, signalK, prevSignal);
         outMACD[outIdx] = macdValue;
         outMACDSignal[outIdx] = prevSignal;
         outMACDHist[outIdx] = macdValue - prevSignal;
