      tempReal = e3;
      for( i = optInTimePeriod - 1; i > 0; i -= 1 ) {
         e1 = Math.fma(one_minus_k, e1, k * (double)inReal[today++]);
         e2 = Math.fma(one_minus_k, e2, k * e1);
         e3 = Math.fma(one_minus_k, e3, k * e2);
         tempReal += e3;
      }
      e4 = tempReal / optInTimePeriod;
      tempReal = e4;
      for( i = optInTimePeriod - 1; i > 0; i -= 1 ) {
         e1 = Math.fma(one_minus_k, e1, k * (double)inReal[today++]);
         e2 = Math.fma(one_minus_k, e2, k * e1);
         e3 = Math.fma(one_minus_k, e3, k * e2);
         e4 = Math.fma(one_minus_k, e4, k * e3);
         tempReal += e4;
      }
